config.generatedSceneCode:
ctx.lineCap = "round";
ctx.lineJoin = "round";

var palette = {
  primary: "#2563EB",
  secondary: "#16A34A",
  highlight: "#F59E0B",
  neutral: "#94A3B8",
  danger: "#DC2626"
};

var panelBg = "rgba(250, 245, 235, 0.92)";
var panelBorder = "rgba(0, 0, 0, 0.1)";
var textPrimary = "#1e293b";
var textMuted = "#64748b";

runtimeState.params = runtimeState.params || {};
if (runtimeState.params.numTokens == null) runtimeState.params.numTokens = 6;
if (runtimeState.params.temperature == null) runtimeState.params.temperature = 1.0;
if (runtimeState.params.selectedQuery == null) runtimeState.params.selectedQuery = 1;
if (runtimeState.params.causalMask == null) runtimeState.params.causalMask = 1;
if (runtimeState.params.keyQueryAlignment == null) runtimeState.params.keyQueryAlignment = 0.6;
if (runtimeState.params.stepIndex == null) runtimeState.params.stepIndex = 0;

var numTokens = Math.max(3, Math.min(12, Math.round(runtimeState.params.numTokens)));
var temperature = Math.max(0.2, Math.min(2.5, runtimeState.params.temperature));
var selectedQuery = Math.max(1, Math.min(numTokens, Math.round(runtimeState.params.selectedQuery)));
var causalMask = runtimeState.params.causalMask ? 1 : 0;
var keyQueryAlignment = Math.max(0, Math.min(1, runtimeState.params.keyQueryAlignment));
var stepIndex = Math.max(0, Math.min(4, Math.round(runtimeState.params.stepIndex)));

runtimeState.params.numTokens = numTokens;
runtimeState.params.temperature = temperature;
runtimeState.params.selectedQuery = selectedQuery;
runtimeState.params.causalMask = causalMask;
runtimeState.params.keyQueryAlignment = keyQueryAlignment;
runtimeState.params.stepIndex = stepIndex;

var w = canvas.width, h = canvas.height;
var pad = 24;
var panelW = Math.min(360, w * 0.34);
var panelH = 310;
var controlsX = pad;
var controlsY = pad;

var mapX = panelW + pad * 2;
var mapY = pad + 24;
var mapW = w - mapX - pad;
var rowY = mapY + 72;
var rowW = Math.max(220, mapW - 20);
var tokenGap = rowW / Math.max(1, (numTokens - 1));

var qIndex = selectedQuery - 1;
var qx = mapX + 10 + tokenGap * qIndex;
var qy = rowY;
var keyY = rowY + 120;
var valY = rowY + 220;

function roundedRect(x, y, rw, rh, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + rw, y, x + rw, y + rh, r);
  ctx.arcTo(x + rw, y + rh, x, y + rh, r);
  ctx.arcTo(x, y + rh, x, y, r);
  ctx.arcTo(x, y, x + rw, y, r);
  ctx.closePath();
}

function drawLabel(txt, x, y, color) {
  ctx.fillStyle = color || textMuted;
  ctx.font = "11px system-ui, sans-serif";
  ctx.textAlign = "left";
  ctx.textBaseline = "alphabetic";
  ctx.fillText((txt || "").toUpperCase(), x, y);
}

function slider(id, label, min, max, step, val, y) {
  var lx = controlsX + 16;
  var ly = y;
  drawLabel(label, lx, ly, textMuted);
  var sx = lx;
  var sy = ly + 10;
  var sw = panelW - 32;
  var t = (val - min) / (max - min);
  var hx = sx + sw * t;

  ctx.strokeStyle = "rgba(148,163,184,0.45)";
  ctx.lineWidth = 4;
  ctx.beginPath(); ctx.moveTo(sx, sy); ctx.lineTo(sx + sw, sy); ctx.stroke();

  ctx.strokeStyle = palette.primary;
  ctx.beginPath(); ctx.moveTo(sx, sy); ctx.lineTo(hx, sy); ctx.stroke();

  ctx.fillStyle = "#ffffff";
  ctx.strokeStyle = palette.primary;
  ctx.lineWidth = 2;
  ctx.beginPath(); ctx.arc(hx, sy, 6, 0, Math.PI * 2); ctx.fill(); ctx.stroke();

  ctx.fillStyle = textPrimary;
  ctx.font = "700 12px ui-monospace, monospace";
  ctx.fillText((typeof val === "number" ? val.toFixed(step < 1 ? 2 : 0) : String(val)), sx + sw - 46, sy + 18);

  var mx = runtimeState.pointer && runtimeState.pointer.x;
  var my = runtimeState.pointer && runtimeState.pointer.y;
  var down = runtimeState.pointer && runtimeState.pointer.down;
  if (down && mx >= sx - 8 && mx <= sx + sw + 8 && my >= sy - 10 && my <= sy + 10) {
    var nt = Math.max(0, Math.min(1, (mx - sx) / sw));
    var nv = min + nt * (max - min);
    nv = Math.round(nv / step) * step;
    runtimeState.params[id] = nv;
  }
}

var keys = [];
var vals = [];
var scores = [];
var masked = [];
for (var i = 0; i < numTokens; i++) {
  var phase = i * 0.8 + time * 1.2;
  keys[i] = Math.sin(phase) * 0.35 + Math.cos(phase * 0.6) * 0.25;
  vals[i] = Math.cos(phase * 0.7) * 0.7 + Math.sin(phase * 0.4) * 0.2;
}
for (var j = 0; j < numTokens; j++) {
  var dist = Math.abs(j - qIndex) / Math.max(1, numTokens - 1);
  var align = (1 - dist) * keyQueryAlignment + (1 - keyQueryAlignment) * (0.35 + 0.65 * (0.5 + 0.5 * Math.sin(time + j)));
  var s = align * 3 - 1.2;
  var m = causalMask === 1 && j > qIndex;
  masked[j] = m;
  scores[j] = m ? -1e9 : s / temperature;
}
var maxS = -1e9;
for (var k = 0; k < numTokens; k++) if (scores[k] > maxS) maxS = scores[k];
var exps = [], sumE = 0;
for (var a = 0; a < numTokens; a++) {
  exps[a] = masked[a] ? 0 : Math.exp(scores[a] - maxS);
  sumE += exps[a];
}
var attn = [];
for (var b = 0; b < numTokens; b++) attn[b] = sumE > 0 ? exps[b] / sumE : 0;
var output = 0;
for (var c = 0; c < numTokens; c++) output += attn[c] * vals[c];

ctx.fillStyle = panelBg;
ctx.strokeStyle = panelBorder;
ctx.lineWidth = 1;
roundedRect(controlsX, controlsY, panelW, panelH, 12); ctx.fill(); ctx.stroke();

ctx.fillStyle = textPrimary;
ctx.font = "10px system-ui, sans-serif";
ctx.fillText("ATTENTION CONTROLS", controlsX + 16, controlsY + 22);

slider("numTokens", "Number of Tokens", 3, 12, 1, numTokens, controlsY + 44);
slider("temperature", "Softmax Temperature", 0.2, 2.5, 0.01, temperature, controlsY + 94);
slider("selectedQuery", "Selected Query Token", 1, numTokens, 1, selectedQuery, controlsY + 144);
slider("keyQueryAlignment", "Q-K Alignment Strength", 0, 1, 0.01, keyQueryAlignment, controlsY + 194);

var tx = controlsX + 16, ty = controlsY + 248, tw = 170, th = 28;
ctx.fillStyle = causalMask ? palette.primary : "rgba(148,163,184,0.2)";
ctx.strokeStyle = panelBorder;
roundedRect(tx, ty, tw, th, 6); ctx.fill(); ctx.stroke();
ctx.fillStyle = causalMask ? "#ffffff" : textPrimary;
ctx.font = "11px system-ui, sans-serif";
ctx.fillText("CAUSAL MASK: " + (causalMask ? "ON" : "OFF"), tx + 10, ty + 18);
var p = runtimeState.pointer;
if (p && p.clicked && p.x >= tx && p.x <= tx + tw && p.y >= ty && p.y <= ty + th) runtimeState.params.causalMask = causalMask ? 0 : 1;

// SCAFFOLD STEP 1: Click a token to set it as the Selected Query, then drag the Selected Query Token slider to compare different tokens.
// SCAFFOLD STEP 2: Slowly move Q–K Alignment Strength from low to high and observe how the highlighted attention links change.
// SCAFFOLD STEP 3: Adjust Softmax Temperature from 2.0 down to 0.3 and watch weights become more peaky.
// SCAFFOLD STEP 4: Toggle Causal Mask off and on; compare which links become blocked (red/disabled) and how the output changes.
// SCAFFOLD STEP 5: Increase Number of Tokens to 10–12 and find a token whose attention becomes split across multiple sources by tuning temperature.
var steps = [
  { i: "Click a token or move SELECTED QUERY TOKEN slider.", c: "Attention is computed per query token.", done: selectedQuery !== 1 },
  { i: "Raise Q-K ALIGNMENT toward high values.", c: "Higher Q·K similarity gives larger weights.", done: keyQueryAlignment >= 0.85 },
  { i: "Lower TEMPERATURE toward 0.3.", c: "Lower temperature makes attention sharper.", done: temperature <= 0.5 },
  { i: "Toggle CAUSAL MASK and compare blocked links.", c: "Masking blocks illegal positions (future tokens).", done: causalMask === 1 },
  { i: "Set TOKENS to 10-12 and broaden with temperature.", c: "Attention can split over multiple relevant values.", done: numTokens >= 10 && temperature >= 1.2 }
];

var spW = Math.min(380, w * 0.35), spH = 170, spX = w - spW - pad, spY = pad;
ctx.fillStyle = panelBg; ctx.strokeStyle = panelBorder;
roundedRect(spX, spY, spW, spH, 12); ctx.fill(); ctx.stroke();
ctx.fillStyle = textPrimary; ctx.font = "10px system-ui, sans-serif";
ctx.fillText("SCAFFOLDED STEPS", spX + 16, spY + 22);
ctx.font = "11px system-ui, sans-serif";
ctx.fillStyle = textMuted;
ctx.fillText(("Step " + (stepIndex + 1) + " / " + steps.length).toUpperCase(), spX + 16, spY + 42);
ctx.fillStyle = textPrimary;
ctx.fillText(steps[stepIndex].i.toUpperCase(), spX + 16, spY + 66);
ctx.fillStyle = textMuted;
ctx.font = "italic 14px Georgia, 'Times New Roman', serif";
ctx.fillText(steps[stepIndex].c, spX + 16, spY + 92);
ctx.font = "700 12px ui-monospace, monospace";
ctx.fillStyle = steps[stepIndex].done ? "#16A34A" : "#DC2626";
ctx.fillText(steps[stepIndex].done ? "Condition met" : "Condition not met", spX + 16, spY + 116);

var blx = spX + 16, bly = spY + 132, bw = 34, bh = 24;
var brx = blx + 44;
ctx.fillStyle = "rgba(255,255,255,0.7)"; ctx.strokeStyle = panelBorder;
roundedRect(blx, bly, bw, bh, 6); ctx.fill(); ctx.stroke();
roundedRect(brx, bly, bw, bh, 6); ctx.fill(); ctx.stroke();
ctx.fillStyle = textPrimary; ctx.font = "11px system-ui, sans-serif";
ctx.fillText("←", blx + 12, bly + 16); ctx.fillText("→", brx + 12, bly + 16);
if (p && p.clicked && p.x >= blx && p.x <= blx + bw && p.y >= bly && p.y <= bly + bh) runtimeState.params.stepIndex = Math.max(0, stepIndex - 1);
if (p && p.clicked && p.x >= brx && p.x <= brx + bw && p.y >= bly && p.y <= bly + bh) runtimeState.params.stepIndex = Math.min(steps.length - 1, stepIndex + 1);

ctx.strokeStyle = "rgba(148,163,184,0.4)";
ctx.lineWidth = 1.2;
for (var g = 0; g < numTokens; g++) {
  var gx = mapX + 10 + tokenGap * g;
  ctx.beginPath(); ctx.moveTo(gx, rowY - 26); ctx.lineTo(gx, valY + 26); ctx.stroke();
}

function tokenNode(x, y, label, active, fill) {
  ctx.beginPath(); ctx.arc(x, y, active ? 13 : 10, 0, Math.PI * 2);
  ctx.fillStyle = fill; ctx.fill();
  ctx.strokeStyle = active ? palette.highlight : "rgba(148,163,184,0.7)";
  ctx.lineWidth = active ? 3 : 1.5;
  ctx.stroke();
  ctx.fillStyle = textPrimary;
  ctx.font = "700 11px ui-monospace, monospace";
  ctx.textAlign = "center";
  ctx.fillText(label, x, y + 4);
}

for (var t = 0; t < numTokens; t++) {
  var x = mapX + 10 + tokenGap * t;
  tokenNode(x, qy, "Q" + (t + 1), t === qIndex, t === qIndex ? "#fde68a" : "#ffffff");
  tokenNode(x, keyY, "K" + (t + 1), false, "#f8fafc");
  tokenNode(x, valY, "V" + (t + 1), false, "#ecfdf5");

  if (p && p.clicked && Math.hypot((p.x - x), (p.y - qy)) < 16) runtimeState.params.selectedQuery = t + 1;
}

for (var e = 0; e < numTokens; e++) {
  var kx = mapX + 10 + tokenGap * e;
  var wgt = attn[e];
  var blocked = masked[e];
  ctx.beginPath();
  ctx.moveTo(qx, qy + 12);
  var cx = (qx + kx) * 0.5;
  var cy = qy + 30 + 26 * Math.sin(time * 2 + e * 0.7);
  ctx.quadraticCurveTo(cx, cy, kx, keyY - 12);
  ctx.strokeStyle = blocked ? "rgba(220,38,38,0.85)" : "rgba(37,99,235," + (0.25 + wgt * 0.85) + ")";
  ctx.lineWidth = blocked ? 2 : (1.5 + wgt * 8);
  ctx.stroke();

  if (!blocked) {
    var tt = (time * 0.6 + e * 0.17) % 1;
    var px = (1 - tt) * (1 - tt) * qx + 2 * (1 - tt) * tt * cx + tt * tt * kx;
    var py = (1 - tt) * (1 - tt) * (qy + 12) + 2 * (1 - tt) * tt * cy + tt * tt * (keyY - 12);
    ctx.beginPath(); ctx.arc(px, py, 2.8, 0, Math.PI * 2); ctx.fillStyle = palette.primary; ctx.fill();
  }

  ctx.fillStyle = blocked ? palette.danger : palette.primary;
  ctx.font = "700 10px ui-monospace, monospace";
  ctx.textAlign = "center";
  ctx.fillText(blocked ? "MASK" : wgt.toFixed(2), kx, keyY - 20);
}

ctx.textAlign = "left";
ctx.fillStyle = textMuted; ctx.font = "11px system-ui, sans-serif";
ctx.fillText("QUERIES", mapX + 10, qy - 24);
ctx.fillText("KEYS", mapX + 10, keyY - 24);
ctx.fillText("VALUES", mapX + 10, valY - 24);

ctx.fillStyle = textPrimary;
ctx.font = "italic 16px Georgia, 'Times New Roman', serif";
ctx.fillText("softmax(QK^T / T) · V", mapX + 10, valY + 52);
ctx.font = "700 13px ui-monospace, monospace";
ctx.fillStyle = palette.secondary;
ctx.fillText("Output(" + selectedQuery + ") = " + output.toFixed(3), mapX + 230, valY + 52);
